diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..0d5f93117172 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,57 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, threshold_C
+  // This transforms a comparison of a truncated value to a comparison
+  // in the original type with an adjusted threshold.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    // Only handle scalar types for now
+    if (!OpType->isFloatingPointTy() || !X->getType()->isFloatingPointTy())
+      ; // Skip non-FP types
+    else if (OpType->getFPMantissaWidth() == X->getType()->getFPMantissaWidth())
+      ; // Skip if same precision (shouldn't happen with fptrunc)
+    else {
+      const APFloat *C;
+      if (match(Op1, m_APFloat(C))) {
+        // Only handle widening: trunc type has fewer mantissa bits than src type
+        // (i.e., fptrunc double to float, not the other way)
+        if (OpType->getFPMantissaWidth() < X->getType()->getFPMantissaWidth()) {
+          // Skip Inf/NaN for now - threshold computation is complex
+          if (C->isInfinity() || C->isNaN())
+            ;
+          else {
+            // Compute threshold based on predicate
+            // For oge/olt: threshold = midpoint(C, prev_float(C))
+            // For ogt/ole: threshold = midpoint(C, next_float(C))
+            bool UseNextFloat = (Pred == FCmpInst::FCMP_OGT ||
+                                 Pred == FCmpInst::FCMP_OLE);
+
+            // Create a copy of C to compute the adjusted value
+            APFloat AdjustedTrunc = *C;
+            AdjustedTrunc.next(UseNextFloat); // nextDown=true means smaller value
+
+            // Convert both values to source type (e.g., double)
+            const fltSemantics &SrcSem = X->getType()->getFltSemantics();
+            APFloat CInSrc = *C;
+            CInSrc.convert(SrcSem, APFloat::rmNearestTiesToEven);
+
+            APFloat AdjustedInSrc = AdjustedTrunc;
+            AdjustedInSrc.convert(SrcSem, APFloat::rmNearestTiesToEven);
+
+            // Compute midpoint: (C + Adjusted) / 2
+            APFloat Midpoint = CInSrc;
+            Midpoint.add(AdjustedInSrc, APFloat::rmNearestTiesToEven);
+            APFloat Two(SrcSem, 2);
+            Midpoint.divide(Two, APFloat::rmNearestTiesToEven);
+
+            // Create the new constant in source type
+            Constant *ThresholdC = ConstantFP::get(X->getType(), Midpoint);
+            return new FCmpInst(Pred, X, ThresholdC, "", &I);
+          }
+        }
+      }
+    }
+  }
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

